"use client"

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import styles from './pill.module.css';
import { DRUG_SHAPES, COLOR_CLASSES } from '@/src/constants/pillFilters';

export default function PillSearchPage() {
    const [printFront, setPrintFront] = useState('');
    const [drugShape, setDrugShape] = useState('');
    const [colorClass1, setColorClass1] = useState('');
    
    const [results, setResults] = useState<any[]>([]); // 현재 페이지 데이터
    const [loading, setLoading] = useState(false);
    const [hasSearched, setHasSearched] = useState(false);
    
    // ⭐️ 서버 사이드 페이지네이션 상태
    const [currentPage, setCurrentPage] = useState(0); // 0부터 시작
    const [totalPages, setTotalPages] = useState(0);
    const [totalElements, setTotalElements] = useState(0);

    // 검색 실행 (항상 1페이지(인덱스 0)부터 시작)
    const handleSearch = () => {
        if (!printFront.trim() && !drugShape && !colorClass1) {
            alert("최소 하나의 검색 조건을 입력해주세요!");
            return;
        }
        setCurrentPage(0); // 페이지 리셋
        fetchData(0);
    };

    // 데이터 가져오기 함수 (페이지 이동 시에도 사용)
    const fetchData = async (page: number) => {
        setLoading(true);
        setHasSearched(true);
        
        try {
            const response = await axios.get(`http://localhost:8080/api/pill/search`, {
                params: { 
                    printFront: printFront.trim(),
                    drugShape: drugShape === "전체" ? "" : drugShape, 
                    colorClass1: colorClass1 === "전체" ? "" : colorClass1,
                    page: page, // ⭐️ 페이지 번호 전달
                    size: 20    // ⭐️ 20개씩 요청
                }
            });
            
            // Spring Boot Page 객체 구조에 맞춤 (content, totalPages 등)
            setResults(response.data.content);
            setTotalPages(response.data.totalPages);
            setTotalElements(response.data.totalElements);
            
        } catch (error) {
            console.error("검색 실패:", error);
            alert("검색 중 오류가 발생했습니다.");
        } finally {
            setLoading(false);
        }
    };

    // 페이지 변경 핸들러
    const handlePageChange = (newPage: number) => {
        setCurrentPage(newPage);
        fetchData(newPage);
        window.scrollTo(0, 0); // 맨 위로 스크롤
    };

    return (
        <div className={styles.container}>
            {/* ... 헤더 및 검색 필터 부분 (기존과 동일) ... */}
            <header className={styles.header}>
                 <h2 className={styles.title}>💊 스마트 알약 식별 검색</h2>
            </header>
            
            <div className={styles.searchFilter}>
               {/* 입력창들은 그대로 유지하고 버튼에 handleSearch 연결 */}
               {/* ... (중략) ... */}
               <button onClick={handleSearch} className={styles.searchBtn}>검색하기</button>
            </div>

            <div className={styles.resultContainer}>
                {loading ? (
                    <div className={styles.loadingWrapper}>
                        <p>🔍 DB 조회 및 네이버 효능 분석 중...</p>
                    </div>
                ) : results.length > 0 ? (
                    <>
                        <p className={styles.totalCount}>
                            총 <strong>{totalElements}</strong>개의 약 중 현재 <strong>{currentPage + 1}</strong>페이지
                        </p>
                        
                        <div className={styles.pillGrid}>
                            {results.map((pill) => (
                                <div key={pill.itemSeq} className={styles.pillCard}>
                                    <div className={styles.pillImg}>
                                        <img src={pill.itemImage || "/img/no_drug_img.png"} alt={pill.itemName} />
                                    </div>
                                    <div className={styles.pillInfo}>
                                        <span className={styles.entpName}>{pill.entpName}</span>
                                        <h3 className={styles.drugName}>{pill.itemName}</h3>
                                        
                                        {/* ⭐️ 네이버 효능 미리보기 */}
                                        {pill.efficacy && pill.efficacy !== "정보 없음" && (
                                            <div className={styles.efficacyPreview}>
                                                <strong>효능:</strong> {pill.efficacy}
                                            </div>
                                        )}
                                        
                                        <div className={styles.pillTags}>
                                            <span>{pill.drugShape}</span>
                                            <span>{pill.colorClass1}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>

                        {/* ⭐️ 서버 연동 페이지네이션 버튼 */}
                        <div className={styles.pagination}>
                            <button 
                                onClick={() => handlePageChange(Math.max(0, currentPage - 1))}
                                disabled={currentPage === 0}
                            >이전</button>
                            
                            <span style={{ margin: '0 10px', lineHeight: '35px' }}>
                                {currentPage + 1} / {totalPages === 0 ? 1 : totalPages}
                            </span>

                            <button 
                                onClick={() => handlePageChange(Math.min(totalPages - 1, currentPage + 1))}
                                disabled={currentPage >= totalPages - 1}
                            >다음</button>
                        </div>
                    </>
                ) : hasSearched && <div className={styles.noResult}>검색 결과가 없습니다.</div>}
            </div>
        </div>
    );
}